import React, { useState } from "react";

export default function Profile() {
  const [postContent, setPostContent] = useState("");
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState({});

  // Thêm bài viết mới
  const handleAddPost = () => {
    if (!postContent.trim()) return;
    setPosts([{ text: postContent, time: new Date().toLocaleString() }, ...posts]);
    setPostContent("");
  };

  // Thêm bình luận cho bài cụ thể
  const handleAddComment = (index, text) => {
    if (!text.trim()) return;
    const newComments = { ...comments };
    if (!newComments[index]) newComments[index] = [];
    newComments[index].push(text);
    setComments(newComments);
  };

  return (
    <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
      <div className="flex flex-col items-center gap-8 w-full max-w-[1060px]">

        {/* --- THÔNG TIN NGƯỜI DÙNG --- */}
        <div className="bg-[#A2D3FF] w-full p-6 rounded-2xl shadow-lg">
          <div className="flex flex-col items-center bg-[#F7FFFF] p-8 rounded-2xl relative overflow-hidden">
            <div className="flex flex-col items-center z-10">
              <span className="text-black text-3xl font-semibold mb-3">
                Nguyễn Văn A
              </span>

              <div className="flex items-center gap-5">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/tb3lhluz_expires_30_days.png"
                  alt="avatar"
                  className="w-[80px] h-[75px] rounded-full object-cover"
                />
                <div className="flex flex-col items-center">
                  <span className="text-black text-sm mt-2">
                    “Không thời gian – Dương Domic”
                  </span>
                </div>
              </div>
            </div>
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ths2znj7_expires_30_days.png"
              alt="decoration"
              className="absolute bottom-0 left-4 w-[180px] h-[160px] opacity-80"
            />
          </div>
        </div>

        {/* --- ĐĂNG BÀI MỚI --- */}
        <div className="bg-white w-full p-6 rounded-2xl shadow-lg">
          <h2 className="text-xl font-semibold text-gray-800 mb-3">Đăng bài mới</h2>
          <textarea
            value={postContent}
            onChange={(e) => setPostContent(e.target.value)}
            placeholder="Bạn đang nghĩ gì vậy?"
            className="w-full p-3 border border-gray-300 rounded-lg resize-none text-black"
            rows="3"
          ></textarea>
          <div className="flex justify-end mt-3">
            <button
              onClick={handleAddPost}
              className="bg-blue-500 hover:bg-blue-600 text-white px-5 py-2 rounded-lg transition-all"
            >
              Đăng
            </button>
          </div>
        </div>

        {/* --- DANH SÁCH BÀI VIẾT --- */}
        {posts.map((post, index) => (
          <div
            key={index}
            className="bg-[#FFFFFF] w-full p-5 rounded-2xl shadow-md flex flex-col gap-3"
          >
            {/* Nội dung bài */}
            <div className="flex items-center gap-3">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/tb3lhluz_expires_30_days.png"
                alt="avatar"
                className="w-[50px] h-[50px] rounded-full"
              />
              <div>
                <p className="font-semibold text-black">Nguyễn Văn A</p>
                <p className="text-xs text-gray-500">{post.time}</p>
              </div>
            </div>

            <p className="text-black bg-gray-50 p-3 rounded-lg border border-gray-200">
              {post.text}
            </p>

            {/* --- Bình luận --- */}
            <div className="flex items-center gap-2 mt-2">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png"
                className="w-[35px] h-[35px] rounded-[10px] cursor-pointer"
                alt="like"
              />
              <input
                type="text"
                placeholder="Viết bình luận..."
                className="flex-1 py-2 px-4 rounded-lg border border-gray-300 text-black"
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    handleAddComment(index, e.target.value);
                    e.target.value = "";
                  }
                }}
              />
            </div>

            {/* Danh sách bình luận */}
            {comments[index]?.length > 0 && (
              <div className="mt-2 ml-12 flex flex-col gap-1">
                {comments[index].map((cmt, idx) => (
                  <span
                    key={idx}
                    className="text-black text-sm bg-gray-100 px-3 py-1 rounded-lg w-fit"
                  >
                    {cmt}
                  </span>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
